                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const currentIndex = serviceKeys.indexOf(serviceId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const prevService = currentIndex > 0 ? serviceKeys[currentIndex - 1] : null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const nextService = currentIndex < serviceKeys.length - 1 ? serviceKeys[currentIndex + 1] : null;

